```java
@Service
public class RazorpayPaymentService {
    private final MeterRegistry registry;
    private final Timer timer;

    RazorpayPaymentService(MeterRegistry registry) {
        this.registry = registry;
        this.timer = Timer.builder("payment.duration")
            .publishPercentiles(0.5, 0.95, 0.99)
            .register(registry);
    }

    public PaymentResult process(String gateway, PaymentRequest req) {
        return timer.record(() -> {
            try {
                PaymentResult r = chargeVia(gateway, req);
                registry.counter("payment.total",
                    "status", "success", "gateway", gateway).increment();
                return r;
            } catch (Exception e) {
                registry.counter("payment.total",
                    "status", "failure", "gateway", gateway).increment();
                throw e;
            }
        });
    }
}
```

